const logoSrc = 'data:image/png;base64,' + LOGO_B64;
['site-logo','footer-logo','admin-logo'].forEach(id => {
  const el = document.getElementById(id);
  if (el) el.src = logoSrc;
});

/* -- HERO SLIDESHOW &#8212; 3 sec per image -- */
(function(){
  const slides = document.querySelectorAll('.slide');
  const dotsWrap = document.getElementById('slideDots');
  let current = 0;
  const total = slides.length;
  const interval = 3000;

  // build dots
  slides.forEach((_,i) => {
    const d = document.createElement('div');
    d.className = 'slide-dot' + (i===0?' active':'');
    d.onclick = () => goTo(i);
    dotsWrap.appendChild(d);
  });

  function goTo(n){
    slides[current].classList.remove('active');
    dotsWrap.children[current].classList.remove('active');
    current = (n + total) % total;
    slides[current].classList.add('active');
    dotsWrap.children[current].classList.add('active');
  }

  // kick off first slide
  slides[0].classList.add('active');
  setInterval(() => goTo(current + 1), interval);
})();

/* GALLERY - copy slide background images to gallery photo cards */
(function(){
  const slides = document.querySelectorAll('.slide');
  const galPhotos = document.querySelectorAll('.gal-photo');
  galPhotos.forEach(function(card, i){
    var slideIdx = i % slides.length;
    if(slides[slideIdx]){
      card.style.backgroundImage = slides[slideIdx].style.backgroundImage;
    }
  });
})();

