/* -- PAGE ROUTING -- */
const pageKeys = ['home','teams','seniors','juniors','miniroos','sponsors','register','fixtures','policies','gallery','contact','admin'];

function showPage(key){
  pageKeys.forEach(k => document.getElementById('page-'+k).classList.remove('active'));
  const el = document.getElementById('page-'+key);
  if(el){ el.classList.add('active'); window.scrollTo({top:0,behavior:'smooth'}); }
  document.querySelectorAll('.nav-link[data-page]').forEach(l => l.classList.toggle('active', l.dataset.page===key));
  document.getElementById('mobileMenu').classList.remove('open');
}

/* -- SCROLL SHADOW -- */
window.addEventListener('scroll', () => {
  document.getElementById('navbar').classList.toggle('scrolled', window.scrollY > 10);
});

/* -- HAMBURGER -- */
function toggleMenu(){ document.getElementById('mobileMenu').classList.toggle('open'); }

/* -- FORM -- */
function handleFormSubmit(){ document.getElementById('form-success').style.display='block'; }

/* -- ADMIN -- */
function handleAdminLogin(){
  const e = document.getElementById('admin-email').value;
  const p = document.getElementById('admin-pass').value;
  const err = document.getElementById('admin-error');
  err.style.display = 'block';
  err.textContent = (!e||!p) ? 'Please enter your email and password.' : 'Backend authentication will be connected in Semester 2.';
}